using System.IO.Ports;
using System.Text;

namespace DiffTest
{
    /// <summary>
    /// л∞ФмљФлУЬ лЭЉл≤® мГЭмД± л∞П нФДл¶∞нД∞ м†ДмЖ° мДЬлєДмК§
    /// FrmMainмЧРмДЬ лґДл¶ђлРЬ лПЕл¶љ нБілЮШмК§
    /// </summary>
    public class BarcodeService
    {
        private readonly MeasureData _data;
        private readonly SerialPort? _printerLH;
        private readonly SerialPort? _printerRH;

        public BarcodeService(MeasureData data, SerialPort? printerLH, SerialPort? printerRH)
        {
            _data = data;
            _printerLH = printerLH;
            _printerRH = printerRH;
        }

        /// <summary>
        /// л∞ФмљФлУЬ лЭЉл≤® мґЬл†• (OK)
        /// VB мЫРл≥Є: 2D л∞ФмљФлУЬ нПђлІЈ + DIFF нПЙкЈ†к∞Т мґЬл†•
        /// </summary>
        public void BarcodePrint(string partNo, string partName, string serialNo, string side)
        {
            LogHelper.Instance.Log("Barcode", $"[OK] мґЬл†• мЛЬмЮС: side={side}, partNo={partNo}, serial={serialNo}");

            try
            {
                var bs = BarcodeSettings.Instance;
                MdbHelper.LoadBarcodeData();

                // 2D л∞ФмљФлУЬ лН∞мЭінД∞ мГЭмД± (VB мЫРл≥Є нПђлІЈ)
                // ZPL ^FH л™Ел†ємЭі _XXл•Љ hexл°Ь нХімДЭнХШлѓАл°Ь лђЄмЮРмЧі кЈЄлМАл°Ь м†ДмЖ°
                const string RS = "_1e";   // Record Separator (^FHк∞А нХімДЭ)
                const string GS = "_1d";   // Group Separator (^FHк∞А нХімДЭ)
                const string EOT = "_04";  // End of Transmission (^FHк∞А нХімДЭ)

                string partNoClean = partNo.Replace("-", "");
                string midSerial1 = serialNo.Length >= 8 ? serialNo.Substring(2, 6) : "";
                string midSerial2 = serialNo.Length >= 15 ? serialNo.Substring(8, 7) : "";

                string barcodeData = $"[)>{RS}06{GS}VPB30{GS}P{partNoClean}{GS}S{GS}E{GS}T{midSerial1}DA1SAA{midSerial2}{GS}M{GS}C{GS}{RS}{EOT}";

                // мДЬлЄМлґАнТИ лН∞мЭінД∞ м°∞нЪМ (мД§м†ХлРЬ мїђлЯЉмЧР к∞ТмЭі мЮИмЬЉл©і #к∞Т нШХнГЬл°Ь мґФк∞А)
                string subPartData = SqlHelper.GetSubPartData(serialNo, bs.SubPartColumns);
                if (!string.IsNullOrEmpty(subPartData))
                {
                    subPartData = SanitizeForZplHex(subPartData);
                    barcodeData += subPartData;
                    LogHelper.Instance.Log("Barcode", $"[OK] мДЬлЄМлґАнТИ мґФк∞А: {subPartData}");
                }

                // DIFF нПЙкЈ†к∞Т к≥ДмВ∞
                string diffData = CalcDiffAverageString(side);

                // л∞ФмљФлУЬ мВђмЭім¶И (+2 VB мЫРл≥Є)
                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;

                // ZPL мГЭмД±
                var sb = new StringBuilder();
                sb.Append("^XA");
                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD{diffData}^FS");
                sb.Append("^XZ");

                string zpl = sb.ToString();
                LogHelper.Instance.Log("Barcode", $"[OK] ZPL мГЭмД±: {zpl.Length}мЮР, diffData={diffData}");

                // нФДл¶∞нД∞ м†ДмЖ°
                if (side == "A" || side == "LH")
                    SendToPrinter(_printerLH, zpl, "LH");
                else if (side == "B" || side == "RH")
                    SendToPrinter(_printerRH, zpl, "RH");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"[OK] мґЬл†• мШ§л•Ш: side={side}", ex);
            }
        }

        /// <summary>
        /// NG л∞ФмљФлУЬ лЭЉл≤® мґЬл†•
        /// VB мЫРл≥Є: л∞ФмљФлУЬмЧР NG м†СлСРмЦі + TQ нХДлУЬмЧР "NG" мґЬл†•
        /// </summary>
        public void BarcodePrintNG(string ngMessage, string partNo, string partName, string serialNo, string side)
        {
            LogHelper.Instance.Log("Barcode", $"[NG] мґЬл†• мЛЬмЮС: side={side}, partNo={partNo}, serial={serialNo}, msg={ngMessage}");

            try
            {
                var bs = BarcodeSettings.Instance;
                MdbHelper.LoadBarcodeData();

                // л∞ФмљФлУЬ лН∞мЭінД∞: NG + мЛЬл¶ђмЦЉ (VB мЫРл≥Є)
                string barcodeData = "NG" + serialNo;

                // л∞ФмљФлУЬ мВђмЭім¶И (+2 VB мЫРл≥Є)
                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;

                // ZPL мГЭмД± (TQ нХДлУЬмЧР "NG" мґФк∞А)
                var sb = new StringBuilder();
                sb.Append("^XA");
                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD{ngMessage}^FS");
                sb.Append($"^FO{bs.TqX},{bs.TqY}^A0N,{bs.TqH},{bs.TqW}^FDNG^FS");
                sb.Append("^XZ");

                string zpl = sb.ToString();
                LogHelper.Instance.Log("Barcode", $"[NG] ZPL мГЭмД±: {zpl.Length}мЮР");

                // нФДл¶∞нД∞ м†ДмЖ°
                if (side == "A" || side == "LH")
                    SendToPrinter(_printerLH, zpl, "LH");
                else if (side == "B" || side == "RH")
                    SendToPrinter(_printerRH, zpl, "RH");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"[NG] мґЬл†• мШ§л•Ш: side={side}", ex);
            }
        }

        /// <summary>
        /// к∞Хм†Ь лЭЉл≤® мґЬл†• (FrmBarcodeмЧРмДЬ нШЄмґЬ)
        /// </summary>
        public void ManualBarcodePrint(string partNo, string partName, string serialNo, string side)
        {
            LogHelper.Instance.Log("Barcode", $"[Manual] мґЬл†• мЛЬмЮС: side={side}, partNo={partNo}, serial={serialNo}");

            try
            {
                var bs = BarcodeSettings.Instance;
                MdbHelper.LoadBarcodeData();

                // 2D л∞ФмљФлУЬ лН∞мЭінД∞ мГЭмД±
                const string RS = "_1e";
                const string GS = "_1d";
                const string EOT = "_04";

                string partNoClean = partNo.Replace("-", "");
                string midSerial1 = serialNo.Length >= 8 ? serialNo.Substring(2, 6) : "";
                string midSerial2 = serialNo.Length >= 15 ? serialNo.Substring(8, 7) : "";

                string barcodeData = $"[)>{RS}06{GS}VPB30{GS}P{partNoClean}{GS}S{GS}E{GS}T{midSerial1}DA1SAA{midSerial2}{GS}M{GS}C{GS}{RS}{EOT}";

                // мДЬлЄМлґАнТИ лН∞мЭінД∞ м°∞нЪМ
                string subPartData = SqlHelper.GetSubPartData(serialNo, bs.SubPartColumns);
                if (!string.IsNullOrEmpty(subPartData))
                {
                    subPartData = SanitizeForZplHex(subPartData);
                    barcodeData += subPartData;
                    LogHelper.Instance.Log("Barcode", $"[Manual] мДЬлЄМлґАнТИ мґФк∞А: {subPartData}");
                }

                // л∞ФмљФлУЬ мВђмЭім¶И (+2 VB мЫРл≥Є)
                int barcodeSize = (int.TryParse(bs.BarcodeSize1, out var s1) ? s1 : 7) + 2;
                int barcodeSize2 = int.TryParse(bs.BarcodeSize2, out var s2) ? s2 : 200;

                // ZPL мГЭмД±
                var sb = new StringBuilder();
                sb.Append("^XA");
                sb.Append($"^FO{bs.BarcodeX},{bs.BarcodeY}^BY5^BXN,{barcodeSize},{barcodeSize2},,,,^FH^FD{barcodeData}^FS");
                sb.Append($"^FO{bs.SerialNoX},{bs.SerialNoY}^A0N,{bs.SerialNoH},{bs.SerialNoW}^FD{serialNo}^FS");
                sb.Append($"^FO{bs.PartNoX},{bs.PartNoY}^A0N,{bs.PartNoH},{bs.PartNoW}^FD{partNo}^FS");
                sb.Append($"^FO{bs.PartNameX},{bs.PartNameY}^A0N,{bs.PartNameH},{bs.PartNameW}^FD{partName}^FS");
                sb.Append($"^FO{bs.CompanyX},{bs.CompanyY}^A0N,{bs.CompanyH},{bs.CompanyW}^FD ^FS");  // к∞Хм†ЬмґЬл†•мЭА лєИк∞Т
                sb.Append("^XZ");

                string zpl = sb.ToString();
                LogHelper.Instance.Log("Barcode", $"[Manual] ZPL мГЭмД±: {zpl.Length}мЮР");

                // нФДл¶∞нД∞ м†ДмЖ°
                if (side == "A" || side == "LH")
                    SendToPrinter(_printerLH, zpl, "LH");
                else if (side == "B" || side == "RH")
                    SendToPrinter(_printerRH, zpl, "RH");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"[Manual] мґЬл†• мШ§л•Ш: side={side}", ex);
            }
        }

        /// <summary>
        /// DIFF нПЙкЈ†к∞Т лђЄмЮРмЧі мГЭмД±
        /// VB мЫРл≥Є: "F:{fwd}mm B:{bwd}mm D:{end}mm Lever:{lever}Kg"
        /// </summary>
        public string CalcDiffAverageString(string side)
        {
            try
            {
                double fwdSum = 0, bwdSum = 0, endSum = 0;
                int fwdCnt = 0, bwdCnt = 0, endCnt = 0;

                for (int i = 0; i < 5; i++)
                {
                    if (!string.IsNullOrEmpty(_data.ValDiffFwd[i]) && double.TryParse(_data.ValDiffFwd[i], out double fv))
                    {
                        fwdSum += fv; fwdCnt++;
                    }
                    if (!string.IsNullOrEmpty(_data.ValDiffBwd[i]) && double.TryParse(_data.ValDiffBwd[i], out double bv))
                    {
                        bwdSum += bv; bwdCnt++;
                    }
                    if (!string.IsNullOrEmpty(_data.ValDiffEnd[i]) && double.TryParse(_data.ValDiffEnd[i], out double ev))
                    {
                        endSum += ev; endCnt++;
                    }
                }

                string fwdAvg = fwdCnt > 0 ? (fwdSum / fwdCnt).ToString("F1") : "0.0";
                string bwdAvg = bwdCnt > 0 ? (bwdSum / bwdCnt).ToString("F1") : "0.0";
                string endAvg = endCnt > 0 ? (endSum / endCnt).ToString("F1") : "0.0";

                string lever = (side == "A" || side == "RH")
                    ? _data.ValueLever.ToString("F1")
                    : _data.ValueLeverB.ToString("F1");

                // WAV мВђмЦСмЭА к∞БлПД(¬∞) нСЬкЄ∞, кЈЄ мЩЄлКФ Kg нСЬкЄ∞
                string optionType = (side == "A" || side == "LH") ? _data.OptionTypeA : _data.OptionTypeB;
                string leverUnit = optionType == "3-WAV" ? "¬∞" : "Kg";

                return $"F:{fwdAvg}mm B:{bwdAvg}mm D:{endAvg}mm Lever:{lever}{leverUnit}";
            }
            catch
            {
                return "";
            }
        }

        /// <summary>
        /// нФДл¶∞нД∞л°Ь ZPL м†ДмЖ°
        /// </summary>
        private void SendToPrinter(SerialPort? printer, string zpl, string printerName)
        {
            if (printer == null || !printer.IsOpen)
            {
                LogHelper.Instance.Log("Barcode", $"нФДл¶∞нД∞ лѓЄмЧ∞к≤∞: {printerName}");
                return;
            }

            try
            {
                printer.Write(zpl);
                LogHelper.Instance.Log("Barcode", $"нФДл¶∞нД∞ м†ДмЖ° мЩДл£М: {printerName}, port={printer.PortName}");
            }
            catch (Exception ex)
            {
                LogHelper.Instance.LogError("Barcode", $"нФДл¶∞нД∞ м†ДмЖ° мШ§л•Ш: {printerName}", ex);
            }
        }
    }
