                string endAvg = endCnt > 0 ? (endSum / endCnt).ToString("F1") : "0.0";

                string lever = (side == "A" || side == "RH")
                    ? _data.ValueLever.ToString("F1")
                    : _data.ValueLeverB.ToString("F1");

