private static string SanitizeForZplHex(string input)
{
    var sb = new StringBuilder(input.Length);
    foreach (char c in input)
    {
        switch ((int)c)
        {
            case 0x04: sb.Append("_04"); break; // EOT
            case 0x1D: sb.Append("_1d"); break; // GS
            case 0x1E: sb.Append("_1e"); break; // RS
            default:   sb.Append(c);     break;
        }
    }
    return sb.ToString();
}

